from django.apps import apps

def get_user_orders(user_id: int) -> list:
    Order = apps.get_model('orders', 'Order')
    return list(Order.objects.filter(user_id=user_id).select_related('items'))

# Python 3.12/3.13 — function-scoped lazy import
def generate_report(data: list[dict]) -> bytes:
    from heavy_analytics import ReportGenerator  # Loaded on first call only
    return ReportGenerator(data).render()
